    @Test("one major incident maps to a single Outage with all fields")
    func singleMajorIncident() async throws {
        let dir = makeTempDir()
        mockHTTP(status: 200, body: """
        {
          "incidents": [
            {
              "name": "Elevated errors on /v1/messages",
              "impact": "major",
              "created_at": "2026-04-22T10:15:00.000Z",
